framework_css:
/*
===============================================================================
  Streaming Service Help Center - Global Framework Styles
  Design: Dark, minimalist, cinematic help center inspired by video platforms.
===============================================================================
*/

:root {
    /* Core palette (extracted / aligned with design) */
    --color-bg-page: #000000;        /* main page background */
    --color-bg-elevated: #111111;    /* elevated sections */
    --color-bg-header: #000000;      /* header bar */
    --color-bg-footer: #000000;      /* footer bar */
    --color-border-subtle: #333333;  /* subtle borders (search box etc.) */
    --color-border-hard: #1E1E1E;    /* header/footer dividers */

    --color-text-primary: #FFFFFF;   /* primary on dark */
    --color-text-muted: #CCCCCC;     /* secondary text */
    --color-text-soft: #888888;      /* tertiary text */

    --color-link-default: #FFFFFF;
    --color-link-hover: #CCCCCC;
    --color-link-accent: #43B0D4;    /* accent for focus / important links */

    --color-success: #2ECC71;
    --color-error:   #E74C3C;
    --color-warning: #F1C40F;
    --color-info:    #3498DB;

    /* Typography */
    --font-heading: "Space Grotesk", Helvetica, sans-serif;
    --font-body: "Source Sans 3", Arial, sans-serif;
    --font-code: "Source Code Pro", SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace;

    --font-size-h1: 26px;
    --font-size-h2: 22px;
    --font-size-h3: 18px;
    --font-size-body: 14px;
    --font-size-small: 12px;

    --font-weight-light: 300;
    --font-weight-regular: 400;
    --font-weight-medium: 500;
    --font-weight-semibold: 600;
    --font-weight-bold: 700;

    --line-height-tight: 1.2;
    --line-height-normal: 1.5;
    --line-height-relaxed: 1.75;

    /* Spacing scale (8px base) */
    --space-0-5: 4px;
    --space-1: 8px;
    --space-2: 16px;
    --space-3: 24px;
    --space-4: 32px;
    --space-5: 48px;
    --space-6: 64px;

    /* Layout */
    --layout-max-width: 1120px;
    --header-vertical-padding: 12px;    /* matches slim cinematic header */
    --footer-vertical-padding: 24px;
}

/* Global reset / base ------------------------------------------------------ */

*, *::before, *::after {
    box-sizing: border-box;
}

html,
body {
    margin: 0;
    padding: 0;
}

body.app-root {
    min-height: 100vh;
    background-color: var(--color-bg-page);
    color: var(--color-text-primary);
    font-family: var(--font-body);
    font-size: var(--font-size-body);
    font-weight: var(--font-weight-regular);
    line-height: var(--line-height-normal);
    -webkit-font-smoothing: antialiased;
}

img {
    max-width: 100%;
    height: auto;
    border-style: none;
}

a {
    color: var(--color-link-default);
    text-decoration: none;
    transition: color 120ms ease-out;
}

a:hover {
    color: var(--color-link-hover);
}

a:focus-visible {
    outline: 2px solid var(--color-link-accent);
    outline-offset: 2px;
}

code,
pre,
kbd,
samp {
    font-family: var(--font-code);
}

main.site-main {
    background-color: var(--color-bg-elevated);
    min-height: calc(100vh - 56px - 96px); /* rough header/footer heights */
}

/* Layout wrappers ---------------------------------------------------------- */

.header-inner,
.footer-inner,
.site-main {
    max-width: var(--layout-max-width);
    margin: 0 auto;
    padding-left: var(--space-3);
    padding-right: var(--space-3);
}

/* Header ------------------------------------------------------------------- */

.site-header {
    background-color: var(--color-bg-header);
    color: var(--color-text-primary);
    border-bottom: 1px solid var(--color-border-hard);
}

.header-inner {
    display: flex;
    align-items: center;
    justify-content: flex-start;
    padding-top: var(--header-vertical-padding);
    padding-bottom: var(--header-vertical-padding);
}

.brand {
    flex: 0 0 auto;
}

.brand-link {
    font-family: var(--font-heading);
    font-weight: var(--font-weight-bold);
    font-size: 18px;
    letter-spacing: 0.18em; /* strong utilitarian caps */
    text-transform: uppercase;
    white-space: nowrap;
}

.brand-link:hover {
    color: var(--color-link-default); /* logo remains stable on hover */
}

.primary-nav {
    flex: 1 1 auto;
    margin-left: var(--space-3);
}

.primary-nav-list {
    list-style: none;
    margin: 0;
    padding: 0;
    display: flex;
    align-items: center;
    justify-content: flex-start;
    gap: var(--space-3);
}

.primary-nav-item {
    flex: 0 0 auto;
}

.primary-nav-link {
    font-family: var(--font-heading);
    font-size: 12px;
    font-weight: var(--font-weight-medium);
    letter-spacing: 0.12em;
    text-transform: uppercase;
    color: var(--color-text-muted);
    padding-bottom: 2px; /* subtle underline alignment */
}

.primary-nav-link:hover {
    color: var(--color-text-primary);
    text-decoration: none;
}

.primary-nav-link[aria-current="page"] {
    color: var(--color-text-primary);
    border-bottom: 2px solid var(--color-link-accent);
}

/* Main content shell ------------------------------------------------------- */

.site-main {
    padding-top: var(--space-4);
    padding-bottom: var(--space-5);
}

/* Footer ------------------------------------------------------------------- */

.site-footer {
    background-color: var(--color-bg-footer);
    color: var(--color-text-soft);
    border-top: 1px solid var(--color-border-hard);
}

.footer-inner {
    padding-top: var(--footer-vertical-padding);
    padding-bottom: var(--footer-vertical-padding);
}

.footer-nav {
    margin-bottom: var(--space-2);
}

.footer-links {
    list-style: none;
    margin: 0;
    padding: 0;
    display: flex;
    flex-wrap: wrap;
    gap: var(--space-1) var(--space-3);
}

.footer-link-item {
    position: relative;
}

.footer-link {
    font-size: var(--font-size-small);
    text-transform: uppercase;
    letter-spacing: 0.08em;
    color: var(--color-text-muted);
}

.footer-link:hover {
    color: var(--color-text-primary);
    text-decoration: none;
}

.footer-meta {
    border-top: 1px solid var(--color-border-subtle);
    padding-top: var(--space-2);
}

.footer-meta-text {
    margin: 0;
    font-size: var(--font-size-small);
    color: var(--color-text-soft);
}

/* Utility classes --------------------------------------------------------- */

.u-visually-hidden {
    position: absolute;
    width: 1px;
    height: 1px;
    padding: 0;
    margin: -1px;
    overflow: hidden;
    clip: rect(0, 0, 0, 0);
    white-space: nowrap;
    border: 0;
}

/* Basic responsiveness ---------------------------------------------------- */

@media (max-width: 960px) {
    .header-inner {
        flex-wrap: wrap;
        row-gap: var(--space-1);
    }

    .primary-nav {
        flex-basis: 100%;
        margin-left: 0;
        margin-top: var(--space-1);
    }

    .primary-nav-list {
        flex-wrap: wrap;
        gap: var(--space-1) var(--space-2);
    }
}

@media (max-width: 640px) {
    .header-inner,
    .footer-inner,
    .site-main {
        padding-left: var(--space-2);
        padding-right: var(--space-2);
    }

    .brand-link {
        font-size: 16px;
        letter-spacing: 0.14em;
    }

    .footer-links {
        gap: var(--space-1) var(--space-2);
    }
}
